SELECT count(*) FROM title, kind_type, movie_keyword, movie_companies, keyword, cast_info, name, movie_info, aka_name WHERE title.kind_id = kind_type.id AND movie_keyword.movie_id = title.id AND movie_companies.movie_id = title.id AND movie_keyword.keyword_id = keyword.id AND cast_info.movie_id = title.id AND cast_info.person_id = name.id AND movie_info.movie_id = title.id AND aka_name.person_id = name.id;